SELECT c.*, MATCH(c.title, c.body) AGAINST(#{keyword} IN NATURAL LANGUAGE MODE) AS relevance FROM content c WHERE c.status = 'PUBLISHED' AND MATCH(c.title, c.body) AGAINST(#{keyword} IN NATURAL LANGUAGE MODE)
AND c.category_id = #{categoryId}
AND c.published_at >= #{startDate}
AND c.published_at <= #{endDate}
ORDER BY
c.like_count DESC c.favorite_count DESC c.view_count DESC relevance DESC, c.published_at DESC

SELECT COUNT(*)
FROM content c
WHERE c.status = 'PUBLISHED'
AND MATCH(c.title, c.body) AGAINST(#{keyword} IN NATURAL LANGUAGE MODE)

    AND c.category_id = #{categoryId}


    AND c.published_at >= #{startDate}


    AND c.published_at <= #{endDate}
